   860→  /**
   861→   * Get ingestion statistics
   862→   */
   863→  async getIngestionStats(days: number = 7): Promise<{
   864→    totalFiles: number;
   865→    totalRecords: number;
   866→    totalAnomalies: number;
   867→    anomaliesByType: Record<string, number>;
   868→    averageRecordsPerFile: number;
   869→  }> {
   870→    return this.traced('getIngestionStats', async (span) => {
   871→      span.setAttribute('stats.days', days);
   872→
   873→      const since = new Date();
   874→      since.setDate(since.getDate() - days);
   875→
   876→      // Get anomaly counts by type
   877→      const anomalyStats = await this.db
   878→        .select({
   879→          anomalyType: mileageReadings.anomalyType,
   880→          count: sql<number>`count(*)::int`,
   881→        })
   882→        .from(mileageReadings)
   883→        .where(
   884→          and(
   885→            eq(mileageReadings.validationStatus, 'ANOMALY'),
   886→            sql`${mileageReadings.ingestedAt} >= ${since.toISOString()}`
   887→          )
   888→        )
   889→        .groupBy(mileageReadings.anomalyType);
   890→
   891→      const anomaliesByType: Record<string, number> = {};
   892→      let totalAnomalies = 0;
   893→
   894→      for (const stat of anomalyStats) {
   895→        const type = stat.anomalyType ?? 'UNKNOWN';
   896→        anomaliesByType[type] = stat.count;
   897→        totalAnomalies += stat.count;
   898→      }
   899→
   900→      // Get total records count
   901→      const [recordStats] = await this.db
   902→        .select({
   903→          total: sql<number>`count(*)::int`,
   904→          files: sql<number>`count(distinct ${mileageReadings.sourceFile})::int`,
   905→        })
   906→        .from(mileageReadings)
   907→        .where(sql`${mileageReadings.ingestedAt} >= ${since.toISOString()}`);
   908→
   909→      const totalRecords = recordStats?.total ?? 0;
   910→      const totalFiles = recordStats?.files ?? 0;
   911→
   912→      return {
   913→        totalFiles,
   914→        totalRecords,
   915→        totalAnomalies,
   916→        anomaliesByType,
   917→        averageRecordsPerFile: totalFiles > 0 ? Math.round(totalRecords / totalFiles) : 0,
   918→      };
   919→    });
   920→  }
   921→
   922→  // ===========================================================================
   923→  // Utility Methods
   924→  // ===========================================================================
   925→
   926→  /**
   927→   * Split array into chunks
   928→   */
   929→  private chunk<T>(array: T[], size: number): T[][] {
   930→    const chunks: T[][] = [];
   931→    for (let i = 0; i < array.length; i += size) {
   932→      chunks.push(array.slice(i, i + size));
   933→    }
   934→    return chunks;
   935→  }
   936→}
   937→
   938→// =============================================================================
   939→// Singleton Export
   940→// =============================================================================
   941→
   942→let ingestionServiceInstance: IngestionService | null = null;
   943→
   944→export function getIngestionService(): IngestionService {
   945→  if (!ingestionServiceInstance) {
   946→    ingestionServiceInstance = new IngestionService();
   947→  }
