  1495→        })
  1496→        .where(eq(pmSchedule.id, pmScheduleId))
  1497→        .returning();
  1498→
  1499→      // Create audit history
  1500→      const historyRecord: NewPmScheduleHistory = {
  1501→        pmScheduleId,
